## Testing
```rust
#[test]
fn test_build_history_capacity() {
    let history = BuildHistory::new(3);

    // Add 5 builds
    for i in 0..5 {
        history.record_start(format!("project-{}", i), None, "cargo build".to_string());
    }

    // Should only keep 3
    assert_eq!(history.recent(10).len(), 3);

    // Most recent should be project-4
    assert_eq!(history.recent(1)[0].project_id, "project-4");
}

#[test]
fn test_build_completion() {
    let history = BuildHistory::new(10);
    let id = history.record_start("test".to_string(), None, "cargo build".to_string());

    assert!(!history.recent(1)[0].is_complete());

    history.record_complete(&id, BuildOutcome::Success);

    let record = &history.recent(1)[0];
    assert!(record.is_complete());
    assert!(matches!(record.outcome, BuildOutcome::Success));
    assert!(record.duration_ms.is_some());
}

#[test]
fn test_build_stats() {
    let history = BuildHistory::new(10);

    let id1 = history.record_start("p1".to_string(), None, "cmd".to_string());
    history.record_complete(&id1, BuildOutcome::Success);

    let id2 = history.record_start("p2".to_string(), None, "cmd".to_string());
    history.record_complete(&id2, BuildOutcome::Failed { exit_code: 1 });

    let stats = history.stats();
    assert_eq!(stats.total, 2);
    assert_eq!(stats.success, 1);
    assert_eq!(stats.failed, 1);
}
